const express = require('express');
const router = express.Router();

// Data sementara (nanti diganti dengan database)
let mahasiswa = [
  { id: 1, nama: 'Budi Santoso', nim: '2021001', ipk: 3.85 },
  { id: 2, nama: 'Siti Rahayu', nim: '2021002', ipk: 3.70 },
  { id: 3, nama: 'Ahmad Fauzi', nim: '2021003', ipk: 3.55 }
];

// GET /mahasiswa — ambil semua mahasiswa
router.get('/', (req, res) => {
  res.json({
    sukses: true,
    total: mahasiswa.length,
    data: mahasiswa
  });
});

// GET /mahasiswa/:id — ambil satu mahasiswa berdasarkan ID
router.get('/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const mhs = mahasiswa.find(m => m.id === id);

  if (!mhs) {
    return res.status(404).json({
      sukses: false,
      pesan: `Mahasiswa dengan ID ${id} tidak ditemukan`
    });
  }

  res.json({ sukses: true, data: mhs });
});

// POST /mahasiswa — tambah mahasiswa baru
router.post('/', (req, res) => {
  const { nama, nim, ipk } = req.body;

  // Validasi sederhana
  if (!nama || !nim) {
    return res.status(400).json({
      sukses: false,
      pesan: 'Nama dan NIM wajib diisi'
    });
  }

  const mahasiswaBaru = {
    id: mahasiswa.length + 1,
    nama,
    nim,
    ipk: ipk ?? 0
  };

  mahasiswa.push(mahasiswaBaru);
  res.status(201).json({ sukses: true, data: mahasiswaBaru });
});

// PUT /mahasiswa/:id — update seluruh data mahasiswa
router.put('/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const index = mahasiswa.findIndex(m => m.id === id);

  if (index === -1) {
    return res.status(404).json({ sukses: false, pesan: 'Tidak ditemukan' });
  }

  mahasiswa[index] = { id, ...req.body };
  res.json({ sukses: true, data: mahasiswa[index] });
});

// DELETE /mahasiswa/:id — hapus mahasiswa
router.delete('/:id', (req, res) => {
  const id = parseInt(req.params.id);
  const sebelum = mahasiswa.length;
  mahasiswa = mahasiswa.filter(m => m.id !== id);

  if (mahasiswa.length === sebelum) {
    return res.status(404).json({ sukses: false, pesan: 'Tidak ditemukan' });
  }

  res.status(200).json({ sukses: true, pesan: 'Berhasil dihapus' });
});

module.exports = router;

