const cekApiKey = (req, res, next) => {
  const apiKey = req.headers['x-api-key'];

  if (!apiKey || apiKey !== process.env.API_KEY) {
    return res.status(401).json({
      sukses: false,
      pesan: 'API Key tidak valid atau tidak ada'
    });
  }

  next();
};

