const validasiMahasiswa = (req, res, next) => {
  const { nama, nim } = req.body;
  const errors = [];

  if (!nama || nama.trim().length < 3)
    errors.push('Nama minimal 3 karakter');
  if (!nim || !/^\d{7}$/.test(nim))
    errors.push('NIM harus 7 digit angka');

  if (errors.length > 0) {
    return res.status(400).json({ sukses: false, errors });
  }

  // Tambahkan data yang sudah dibersihkan ke req
  req.validatedBody = { nama: nama.trim(), nim };
  next();
};

