const express = require('express');
const app = express();

// ==========================================
// CUSTOM ERROR CLASS
// ==========================================
class AppError extends Error {
  constructor(pesan, statusCode, kode = null) {
    super(pesan);
    this.statusCode = statusCode;
    this.kode = kode;           // kode error untuk client
    this.isOperational = true;  // error yang bisa diprediksi
    Error.captureStackTrace(this, this.constructor);
  }
}

// Error khusus yang sering dipakai
class NotFoundError extends AppError {
  constructor(resource = 'Resource') {
    super(`${resource} tidak ditemukan`, 404, 'NOT_FOUND');
  }
}

class ValidationError extends AppError {
  constructor(pesan) {
    super(pesan, 400, 'VALIDATION_ERROR');
  }
}

class UnauthorizedError extends AppError {
  constructor() {
    super('Anda harus login untuk mengakses ini', 401, 'UNAUTHORIZED');
  }
}

// ==========================================
// CONTOH ROUTE YANG MELEMPAR ERROR
// ==========================================
app.get('/mahasiswa/:id', async (req, res, next) => {
  try {
    const id = parseInt(req.params.id);

    if (isNaN(id)) {
      throw new ValidationError('ID harus berupa angka');
    }

    const mhs = await MahasiswaModel.findById(id);
    if (!mhs) {
      throw new NotFoundError('Mahasiswa');
    }

    res.json({ sukses: true, data: mhs });
  } catch (err) {
    next(err); // teruskan error ke error handler
  }
});

// Async wrapper helper (untuk Express 4)
const asyncHandler = (fn) => (req, res, next) => {
  Promise.resolve(fn(req, res, next)).catch(next);
};

// Pakai asyncHandler — tidak perlu try-catch di setiap route!
app.delete('/mahasiswa/:id', asyncHandler(async (req, res) => {
  const mhs = await MahasiswaModel.findByIdAndDelete(req.params.id);
  if (!mhs) throw new NotFoundError('Mahasiswa');
  res.json({ sukses: true, pesan: 'Berhasil dihapus' });
}));

// ==========================================
// 404 HANDLER — untuk route yang tidak ada
// ==========================================
app.use((req, res, next) => {
  next(new NotFoundError(`Endpoint ${req.method} ${req.path}`));
});

// ==========================================
// ERROR HANDLING MIDDLEWARE (4 parameter!)
// ==========================================
app.use((err, req, res, next) => {
  // Log error di server
  console.error(`[ERROR] ${err.message}`, {
    statusCode: err.statusCode,
    path: req.path,
    stack: err.stack
  });

  // Format response yang konsisten
  const statusCode = err.statusCode || 500;
  const isDev = process.env.NODE_ENV === 'development';

  res.status(statusCode).json({
    sukses: false,
    error: {
      kode: err.kode || 'SERVER_ERROR',
      pesan: err.isOperational
        ? err.message
        : 'Terjadi kesalahan di server. Silakan coba lagi.', // sembunyikan detail
      // Stack trace hanya di development!
      ...(isDev && { stack: err.stack })
    }
  });
});

