const express = require('express');
const cors = require('cors'); // npm install cors
const app = express();

// ==========================================
// CORS SEDERHANA — izinkan semua origin
// ==========================================
app.use(cors()); // HATI-HATI: jangan di production!

// ==========================================
// CORS SPESIFIK — hanya origin tertentu
// ==========================================
const opsiCors = {
  origin: [
    'http://localhost:5173',           // Vite dev server
    'http://localhost:3000',           // React dev server
    'https://web-belajar.vercel.app',  // production frontend
  ],
  methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
  credentials: true,   // izinkan cookies dikirim bersama request
  maxAge: 86400        // cache preflight response selama 24 jam
};

app.use(cors(opsiCors));

// ==========================================
// CORS DINAMIS — dari environment variable
// ==========================================
const originsIzin = process.env.ALLOWED_ORIGINS?.split(',') || [];

app.use(cors({
  origin: (origin, callback) => {
    // Izinkan jika tidak ada origin (misal Postman) atau ada di whitelist
    if (!origin || originsIzin.includes(origin)) {
      callback(null, true);
    } else {
      callback(new Error(`Origin ${origin} tidak diizinkan oleh CORS`));
    }
  }
}));

// ==========================================
